-- Drug name indexes for faster LIKE searches
CREATE INDEX IF NOT EXISTS idx_drug_entries_scientific_name 
  ON drug_entries(scientific_name);

CREATE INDEX IF NOT EXISTS idx_drug_entries_trade_names 
  ON drug_entries(trade_names);

-- ICD code indexes
CREATE INDEX IF NOT EXISTS idx_icd_codes_code 
  ON icd_codes(code);

CREATE INDEX IF NOT EXISTS idx_icd_codes_description 
  ON icd_codes(description);

-- Junction table indexes for faster joins
CREATE INDEX IF NOT EXISTS idx_drug_entry_codes_drug_id 
  ON drug_entry_codes(drug_entry_id);

CREATE INDEX IF NOT EXISTS idx_drug_entry_codes_code_id 
  ON drug_entry_codes(icd_code_id);

-- Search analytics indexes for faster queries
CREATE INDEX IF NOT EXISTS idx_search_analytics_created_at 
  ON search_analytics(created_at);

CREATE INDEX IF NOT EXISTS idx_search_analytics_query 
  ON search_analytics(query);

